// -------------------------------------------------------------------
// Tools
// -------------------------------------------------------------------

public sealed class ResearchTools
{
    private readonly HttpClient _httpClient;
    private readonly List<(string Title, string Content)> _notes = [];

    public ResearchTools(HttpClient httpClient)
    {
        _httpClient = httpClient;
        _httpClient.DefaultRequestHeaders.UserAgent.ParseAdd(
            "ResearchAgent/1.0 (compatible; research bot)");
    }

    [Description("Searches the web for a query and returns result snippets. " +
                 "Use varied queries to get broad coverage of a topic.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await _httpClient.GetStringAsync(url);

            var results = ParseSearchResults(html);
            if (results.Count == 0)
                return "No results found for this query.";

            var sb = new StringBuilder();
            sb.AppendLine($"Search results for: {query}");
            sb.AppendLine();

            foreach (var (title, snippet, link) in results.Take(5))
            {
                sb.AppendLine($"• {title}");
                sb.AppendLine($"  {snippet}");
                if (!string.IsNullOrEmpty(link))
                    sb.AppendLine($"  Source: {link}");
                sb.AppendLine();
            }

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Saves a research note with a title and content for later summarization.")]
    public string SaveNote(
        [Description("Short title for the note")] string title,
        [Description("The note content with key findings")] string content)
    {
        _notes.Add((title, content));
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieves all saved research notes collected so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"--- Note {i + 1}: {_notes[i].Title} ---");
            sb.AppendLine(_notes[i].Content);
            sb.AppendLine();
        }

        return sb.ToString();
    }

    private static List<(string Title, string Snippet, string Link)> ParseSearchResults(
        string html)
    {
        var results = new List<(string, string, string)>();

        // Extract result blocks from DuckDuckGo HTML lite response
        var resultPattern = new Regex(
            @"<a[^>]+class=""result__a""[^>]*href=""(?<url>[^""]*?)""[^>]*>(?<title>.*?)</a>.*?" +
            @"<a[^>]+class=""result__snippet""[^>]*>(?<snippet>.*?)</a>",
            RegexOptions.Singleline | RegexOptions.IgnoreCase);

        foreach (Match match in resultPattern.Matches(html))
        {
            var title = StripHtml(match.Groups["title"].Value);
            var snippet = StripHtml(match.Groups["snippet"].Value);
            var link = ExtractUrl(match.Groups["url"].Value);

            if (!string.IsNullOrWhiteSpace(title))
                results.Add((title, snippet, link));
        }

        return results;
    }

    private static string ExtractUrl(string ddgUrl)
    {
        // DuckDuckGo wraps URLs in a redirect; extract the actual target
        var match = Regex.Match(ddgUrl, @"[?&]uddg=([^&]+)");
        if (match.Success)
            return Uri.UnescapeDataString(match.Groups[1].Value);

        return ddgUrl;
    }

    private static string StripHtml(string html)
    {
        var text = Regex.Replace(html, @"<[^>]+>", "");
        text = System.Net.WebUtility.HtmlDecode(text);
        return text.Trim();
    }
}

